// Guard: validate the Lever discovery HTTP response before proceeding.
// A 504 gateway timeout returns an HTML page — JSON.parse on that throws.
// This node catches that and produces a clean, isolated error so the workflow
// can continue to the Greenhouse step regardless of what Lever did.
const res = $input.first();
const httpStatus = res.json?.statusCode ?? 200;
let body;
try {
  body = typeof res.json?.body === 'string' ? JSON.parse(res.json.body) : (res.json || {});
} catch (parseErr) {
  const raw = String(res.json?.body || '').slice(0, 300);
  console.error('[discovery:lever] Non-JSON response from /discover (likely 504 timeout):', raw);
  return [{ json: { ok: false, source_family: 'lever', error: 'non_json_response', status: httpStatus, raw_preview: raw } }];
}
if (httpStatus === 401) {
  console.error('[discovery:lever] UNAUTHORIZED — check DISCOVERY_SECRET in n8n and Netlify');
  return [{ json: { ok: false, source_family: 'lever', error: 'unauthorized', status: 401 } }];
}
if (httpStatus !== 200 || body.ok === false) {
  console.warn('[discovery:lever] Run failed or skipped:', body.message || body.error || `HTTP ${httpStatus}`);
  return [{ json: { ok: false, source_family: 'lever', error: body.message || body.error || `HTTP ${httpStatus}`, status: httpStatus } }];
}
if (body.mode === 'demo') {
  return [{ json: { ok: true, source_family: 'lever', mode: 'demo' } }];
}
console.log(`[discovery:lever] ${body.total_discovered ?? 0} discovered, ${body.total_ingested ?? 0} ingested`);
return [{ json: { ok: true, source_family: 'lever', ...body } }];

// Guard: validate the Greenhouse discovery HTTP response before proceeding.
// A 504 gateway timeout returns an HTML page — JSON.parse on that throws.
// This node catches that and produces a clean, isolated error.
const res = $input.first();
const httpStatus = res.json?.statusCode ?? 200;
let body;
try {
  body = typeof res.json?.body === 'string' ? JSON.parse(res.json.body) : (res.json || {});
} catch (parseErr) {
  const raw = String(res.json?.body || '').slice(0, 300);
  console.error('[discovery:greenhouse] Non-JSON response from /discover (likely 504 timeout):', raw);
  return [{ json: { ok: false, source_family: 'greenhouse', error: 'non_json_response', status: httpStatus, raw_preview: raw } }];
}
if (httpStatus === 401) {
  console.error('[discovery:greenhouse] UNAUTHORIZED — check DISCOVERY_SECRET in n8n and Netlify');
  return [{ json: { ok: false, source_family: 'greenhouse', error: 'unauthorized', status: 401 } }];
}
if (httpStatus !== 200 || body.ok === false) {
  console.warn('[discovery:greenhouse] Run failed or skipped:', body.message || body.error || `HTTP ${httpStatus}`);
  return [{ json: { ok: false, source_family: 'greenhouse', error: body.message || body.error || `HTTP ${httpStatus}`, status: httpStatus } }];
}
if (body.mode === 'demo') {
  return [{ json: { ok: true, source_family: 'greenhouse', mode: 'demo' } }];
}
console.log(`[discovery:greenhouse] ${body.total_discovered ?? 0} discovered, ${body.total_ingested ?? 0} ingested`);
return [{ json: { ok: true, source_family: 'greenhouse', ...body } }];

// Merge results from both source families into a single summary.
// Lever result is retrieved from the named upstream node; Greenhouse from $input.
// If one source timed out (ok:false), its error is recorded but the other source's
// results are preserved — a single-source failure does not abort the whole run.
const leverResult = $('Guard Lever Response').first().json;
const ghResult = $input.first().json;

const totalDiscovered = (leverResult.total_discovered ?? 0) + (ghResult.total_discovered ?? 0);
const totalIngested = (leverResult.total_ingested ?? 0) + (ghResult.total_ingested ?? 0);
const totalRecommended = (leverResult.total_recommended ?? 0) + (ghResult.total_recommended ?? 0);
const sourcesRun = (leverResult.sources_run ?? 0) + (ghResult.sources_run ?? 0);

const sourceErrors = [];
if (leverResult.ok === false) sourceErrors.push({ source_family: 'lever', error: leverResult.error });
if (ghResult.ok === false) sourceErrors.push({ source_family: 'greenhouse', error: ghResult.error });

const ok = leverResult.ok !== false || ghResult.ok !== false;
const mode = leverResult.mode || ghResult.mode || 'live';

if (sourceErrors.length > 0) {
  console.warn('[discovery] Source-level errors (isolated, other sources unaffected):', JSON.stringify(sourceErrors));
}

console.log(`[discovery] Merged: ${sourcesRun} source(s), ${totalDiscovered} discovered, ${totalIngested} ingested`);

return [{ json: {
  ok,
  mode,
  sources_run: sourcesRun,
  total_discovered: totalDiscovered,
  total_ingested: totalIngested,
  total_recommended: totalRecommended,
  source_errors: sourceErrors,
  lever: leverResult.ok !== false
    ? { discovered: leverResult.total_discovered ?? 0, ingested: leverResult.total_ingested ?? 0 }
    : { error: leverResult.error },
  greenhouse: ghResult.ok !== false
    ? { discovered: ghResult.total_discovered ?? 0, ingested: ghResult.total_ingested ?? 0 }
    : { error: ghResult.error },
} }];

// Forward the discovery_run_complete event summary to webhooks.
// The /webhooks function dispatches to WEBHOOK_URL or WEBHOOK_URL_DISCOVERY_RUN_COMPLETE.
const body = $input.first().json;
return [{ json: {
  event: 'discovery_run_complete',
  payload: {
    sources_run: body.sources_run,
    total_discovered: body.total_discovered,
    total_ingested: body.total_ingested,
    source_errors: body.source_errors || [],
    timestamp: new Date().toISOString()
  }
}}];
